/**
 * Yutome brand icon, embedded as base64 PNG so the Worker can serve it
 * without an asset binding. Two sizes are bundled:
 *   - 48x48  for favicons and inline use on the consent screen
 *   - 256x256 for connector listings, app launchers, etc.
 *
 * Regenerate from docs/assets/yutome-icon.png:
 *   sips -Z 48  docs/assets/yutome-icon.png --out /tmp/y48.png
 *   sips -Z 256 docs/assets/yutome-icon.png --out /tmp/y256.png
 *   base64 /tmp/y48.png  | tr -d '\n'   # paste as ICON_48_BASE64
 *   base64 /tmp/y256.png | tr -d '\n'   # paste as ICON_256_BASE64
 */

export const ICON_48_BASE64 = "";

export const ICON_256_BASE64 = "";

function decodeBase64(b64: string): Uint8Array {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

export function iconResponse(size: 48 | 256): Response {
  const bytes = decodeBase64(size === 48 ? ICON_48_BASE64 : ICON_256_BASE64);
  return new Response(bytes, {
    status: 200,
    headers: {
      "content-type": "image/png",
      "cache-control": "public, max-age=86400, immutable",
      "x-content-type-options": "nosniff",
    },
  });
}
